import type { TreeNode } from '../types'
import type { ASTNode, CallExpressionNode } from './ast.types'
import type { ConvertAstNodeHandlerOptions } from './astToTreeNode.convert.handlers.types'
import { resolveFieldNameFromAst } from './astToTreeNode.convert.helpers'

export function setConditionFieldFromArg(
  node: TreeNode,
  argument: ASTNode | undefined,
  options: ConvertAstNodeHandlerOptions<CallExpressionNode>,
) {
  if (!argument) return

  node.field = resolveFieldNameFromAst(argument)
  if (node.field) {
    node.fieldType = options.context.getFieldTypeForNode(node.field)
  }
}
