import type { TreeNode } from '../../types'
import type { GeneratorContext } from '../nodeExpressionGenerator.types'
import { getFieldConditionDataType } from '../field-mode-value'
import { getAviatorArrayLiteral } from './array-values'

export function generateIpInNetmaskExpression(node: TreeNode, context: GeneratorContext): string {
  const userSelectedDataType = getFieldConditionDataType(node, context)
  const arrayValues = getAviatorArrayLiteral(node.value, userSelectedDataType)
  const expression = `IPScene.isIpInNetmaskList(${node.field}, seq.list(${arrayValues}))`

  if (node.isNegated) {
    return `!${expression}`
  }
  return expression
}
