import type { TreeNode } from '../types'
import { generateFunctionModeExpression } from './nodeExpressionGenerator.function-mode.shared'
import type { GenerateNodeExpressionFn, GeneratorContext } from './nodeExpressionGenerator.types'

export function generateFunctionModeConditionExpression(
  node: TreeNode,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
): string {
  return generateFunctionModeExpression(node, context, generateNodeExpression, {
    call: {
      expandArrayValueParameters: true,
    },
    treatComparisonValueAsField: node.valueIsField === true,
    negationStrategy: 'wrap-final',
  })
}
