export interface TokenizerRuntime {
  input: string
  position: number
  current: string
}

export function createTokenizerRuntime(input: string): TokenizerRuntime {
  return {
    input,
    position: 0,
    current: input[0] || '',
  }
}

export function advance(runtime: TokenizerRuntime): void {
  runtime.position += 1
  runtime.current = runtime.input[runtime.position] || ''
}

export function peek(runtime: TokenizerRuntime, offset = 1): string {
  return runtime.input[runtime.position + offset] || ''
}

export function skipWhitespace(runtime: TokenizerRuntime): void {
  while (runtime.current && /\s/.test(runtime.current)) {
    advance(runtime)
  }
}
