import type { TreeNode } from '../../types'
import type { GeneratorContext } from '../nodeExpressionGenerator.types'
import { generateBelongExpression } from './terminal.belong'
import { generateIpInNetmaskExpression } from './terminal.ip-netmask'
import { generateMatchExpression } from './terminal.match'

interface ResolveTerminalFieldModeOperatorExpressionParams {
  node: TreeNode
  context: GeneratorContext
  formattedValue: unknown
}

export function resolveTerminalFieldModeOperatorExpression(
  params: ResolveTerminalFieldModeOperatorExpressionParams,
): string | null {
  const { node, context, formattedValue } = params

  if (node.comparison === 'isIpInNetmaskList') {
    return generateIpInNetmaskExpression(node, context)
  }

  if (node.comparison === 'belong') {
    return generateBelongExpression(node, context)
  }

  if (node.comparison === 'match') {
    return generateMatchExpression(formattedValue, node.field || '', node.isNegated)
  }

  return null
}
