import type { KeywordLiteralNode, KeywordLiteralValue, LogicalOperator } from '../ast.types'

export function toKeywordLiteral(value: string): KeywordLiteralValue {
  if (value === 'nil' || value === 'null' || value === 'true' || value === 'false') {
    return value
  }
  throw new Error(`Unsupported keyword literal: ${value}`)
}

export function toLogicalOperator(value: string): LogicalOperator {
  if (value === '&&' || value === '||') {
    return value
  }
  throw new Error(`Unsupported logical operator: ${value}`)
}

export function createNilKeywordLiteral(): KeywordLiteralNode {
  return {
    type: 'Literal',
    value: 'nil',
    dataType: 'keyword',
  }
}
