import { resolveFieldNameFromAst } from '../astToTreeNode.convert.helpers'
import type { FunctionModeParameterRuleContext } from './types'
import { assignSimpleParameterValue } from './shared'

export function applyMemberExpressionRule(context: FunctionModeParameterRuleContext): boolean {
  const { arg, index, parameters } = context
  if (arg.type !== 'MemberExpression') return false

  assignSimpleParameterValue(parameters[index], resolveFieldNameFromAst(arg), 'field')
  return true
}
