import { generateExpressionFromAST } from '../astToTreeNode.expression'
import type { FunctionModeParameterRuleContext } from './types'
import { assignSimpleParameterValue } from './shared'

export function applyLambdaRule(context: FunctionModeParameterRuleContext): boolean {
  const { arg, index, parameters } = context
  if (arg.type !== 'LambdaExpression') return false

  assignSimpleParameterValue(parameters[index], generateExpressionFromAST(arg), 'lambda')
  return true
}
