import { classifyIdentifierToken } from './classifier'
import { readIdentifier, readNumber, readString } from './readers'
import type { TokenizerRuntime } from './runtime'
import type { Token } from './types'

export function consumeLiteralOrIdentifier(runtime: TokenizerRuntime, tokens: Token[]): boolean {
  if (runtime.current === '"' || runtime.current === '\'') {
    const value = readString(runtime, runtime.current)
    tokens.push({ type: 'STRING', value })
    return true
  }

  if (/\d/.test(runtime.current)) {
    const value = readNumber(runtime)
    tokens.push({ type: 'NUMBER', value: Number.parseFloat(value) })
    return true
  }

  if (/[a-z_]/i.test(runtime.current)) {
    const value = readIdentifier(runtime)
    tokens.push(classifyIdentifierToken(value))
    return true
  }

  return false
}
