import type { FunctionParameter, TreeNode } from '../../types'
import type { GenerateNodeExpressionFn, GeneratorContext } from '../nodeExpressionGenerator.types'
import { isLambdaExpression } from './constants'
import type { BuildFunctionCallExpressionOptions } from './types'

export function hasParameterContent(param: FunctionParameter): boolean {
  if (param.isNested && param.nestedNode) {
    return true
  }
  return param.value !== undefined && param.value !== ''
}

function resolveParameterType(param: FunctionParameter, context: GeneratorContext): string {
  let currentParamType = param.type || 'value'

  try {
    if (currentParamType === 'value'
      && typeof param.value === 'string'
      && param.value
      && context.availableFields.some((field) => field.value === param.value)) {
      currentParamType = 'field'
    }
  } catch (fieldError: unknown) {
    const message = fieldError instanceof Error ? fieldError.message : String(fieldError)
    console.warn('⚠️ 字段检测失败:', message)
  }

  return currentParamType
}

export function resolveParameterExpressionValue(
  node: TreeNode,
  param: FunctionParameter,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
  options: BuildFunctionCallExpressionOptions,
): unknown {
  if (param.isNested && param.nestedNode) {
    return generateNodeExpression(param.nestedNode, context)
  }

  const currentParamType = resolveParameterType(param, context)
  if (param.value === undefined || param.value === '' || currentParamType !== 'value') {
    return param.value
  }

  if (isLambdaExpression(param.value)) {
    return param.value
  }

  if (Array.isArray(param.value) && options.expandArrayValueParameters) {
    return param.value
  }

  const nodeDataTypes = context.parameterDataTypes.get(node.id)
  const userSelectedDataType = nodeDataTypes?.get(param.name || '') || param.valueType || 'string'

  if (typeof param.value === 'string') {
    if (userSelectedDataType === 'number' || userSelectedDataType === 'boolean') {
      return param.value
    }
    if (!param.value.startsWith('"') && !param.value.startsWith('\'')) {
      return `"${param.value}"`
    }
    return param.value
  }

  if (typeof param.value === 'number') {
    if (userSelectedDataType === 'string') {
      return `"${param.value}"`
    }
    return String(param.value)
  }

  if (typeof param.value === 'boolean') {
    return String(param.value)
  }

  return param.value
}
