/**
 * TreeNode表达式生成器
 * 负责将TreeNode转换为Aviator表达式字符串
 */

import { generateConditionNodeExpression } from './nodeExpressionGenerator.condition'
import { generateFunctionNodeExpression } from './nodeExpressionGenerator.function'
import { generateGroupNodeExpression } from './nodeExpressionGenerator.group'
import type { GenerateNodeExpressionFn, GeneratorContext, GeneratorNode } from './nodeExpressionGenerator.types'

export type { GeneratorContext } from './nodeExpressionGenerator.types'

/**
 * 生成单个节点的表达式
 */
export const generateNodeExpression: GenerateNodeExpressionFn = (
  node: GeneratorNode,
  context: GeneratorContext,
): string => {
  switch (node.type) {
    case 'condition':
      return generateConditionNodeExpression(node, context, generateNodeExpression)

    case 'function':
      return generateFunctionNodeExpression(node, context, generateNodeExpression)

    case 'group':
      return generateGroupNodeExpression(node, context, generateNodeExpression)

    default:
      return ''
  }
}
