import type { FunctionModeParameterRuleContext } from './types'
import { assignSimpleParameterValue } from './shared'

export function applyIdentifierRule(context: FunctionModeParameterRuleContext): boolean {
  const { arg, index, parameters } = context
  if (arg.type !== 'Identifier') return false

  assignSimpleParameterValue(parameters[index], arg.name, 'field')
  return true
}
