import { AVIATOR_FUNCTIONS } from '../../constants'
import type { FunctionModeParameterRuleContext } from './types'

function isNestedReturnTypeCompatible(paramValueType: string | undefined, nestedReturnType?: string): boolean {
  if (paramValueType === 'any') return true
  if (nestedReturnType === paramValueType) return true
  if (paramValueType === 'list' && nestedReturnType === 'list') return true
  if (paramValueType === 'array' && nestedReturnType === 'list') return true
  if (paramValueType === 'list' && nestedReturnType === 'array') return true
  return false
}

export function applyNestedExpressionRule(context: FunctionModeParameterRuleContext): boolean {
  const { arg, index, functionNode, options, parameters } = context
  const nestedNode = options.convert(arg, options.level + 1, functionNode.id)

  if (nestedNode.type === 'condition' && nestedNode.functionName) {
    const nestedFunction = AVIATOR_FUNCTIONS.find((func) => func.name === nestedNode.functionName)
    const nestedReturnType = nestedFunction?.returnType
    const paramValueType = parameters[index].valueType

    if (isNestedReturnTypeCompatible(paramValueType, nestedReturnType)) {
      nestedNode.comparison = undefined
      nestedNode.value = undefined
    }

    parameters[index].type = 'condition'
  } else if (nestedNode.type === 'condition') {
    nestedNode.comparison = undefined
    nestedNode.value = undefined
    parameters[index].type = 'condition'
  }

  parameters[index].nestedNode = nestedNode
  parameters[index].isNested = true
  parameters[index].value = undefined
  return true
}
