import type { ConversionContext } from './astToTreeNode.types'
import { generateFieldNameFromMember } from './astToTreeNode.expression'
import type { ASTNode, LiteralNode } from './ast.types'

export type LiteralDataType = 'string' | 'number' | 'boolean'

export function filterNonNull<T>(value: T | null): value is T {
  return value !== null
}

export function inferLiteralDataType(node: LiteralNode): LiteralDataType {
  if (node.dataType === 'number') return 'number'
  if (node.dataType === 'keyword' && (node.value === 'true' || node.value === 'false')) {
    return 'boolean'
  }
  return 'string'
}

export function isNilLiteral(node: ASTNode): node is LiteralNode {
  return node.type === 'Literal'
    && node.dataType === 'keyword'
    && (node.value === 'nil' || node.value === 'null')
}

export function isEmptyComparableLiteral(node: ASTNode, operator: string): node is LiteralNode {
  return node.type === 'Literal' && node.value === '' && (operator === '==' || operator === '!=')
}

export function setNodeDataType(
  context: ConversionContext,
  nodeId: string,
  key: string,
  dataType: LiteralDataType,
) {
  const nodeDataTypes = context.parameterDataTypes.get(nodeId) || new Map()
  nodeDataTypes.set(key, dataType)
  context.parameterDataTypes.set(nodeId, nodeDataTypes)
}

export function resolveFieldNameFromAst(node: ASTNode): string | undefined {
  if (node.type === 'Identifier') {
    return node.name
  }

  if (node.type === 'MemberExpression') {
    return generateFieldNameFromMember(node)
  }

  if (node.type === 'Literal') {
    return String(node.value)
  }

  return undefined
}

export function resolveSimpleNodeValue(node: ASTNode): string | number | null {
  if (node.type === 'Literal') {
    return node.value
  }

  if (node.type === 'Identifier') {
    return node.name
  }

  return null
}
