import {
  createTokenizerRuntime,
  skipWhitespace,
} from './runtime'
import { consumeNextToken } from './scanners'
import type { Token } from './types'

export type { Token } from './types'

/**
 * 将表达式字符串转换为Token数组
 */
export function tokenizeExpression(input: string): Token[] {
  const tokens: Token[] = []
  const runtime = createTokenizerRuntime(input)

  while (runtime.position < input.length) {
    skipWhitespace(runtime)
    if (!runtime.current) {
      break
    }

    consumeNextToken(runtime, tokens)
  }

  return tokens
}
