import { createConditionNode } from '../utils'
import type { CallExpressionNode } from './ast.types'
import type { AstNodeRuleDefinition } from './astToTreeNode.convert.rule-registry'
import { resolveFieldNameFromAst } from './astToTreeNode.convert.helpers'
import { setConditionFieldFromArg } from './astToTreeNode.convert.call.rule.shared'

function tryHandleStringConditionCall(
  options: Parameters<AstNodeRuleDefinition<CallExpressionNode>['handler']>[0],
) {
  const { node, level, parentId } = options

  const comparisonByFunctionName: Record<string, string> = {
    'string.contains': 'contains',
    'string.startsWith': 'startsWith',
    'string.endsWith': 'endsWith',
    'string.match': 'match',
  }

  const comparison = comparisonByFunctionName[node.callee.name]
  if (!comparison) {
    return null
  }

  const conditionNode = createConditionNode(parentId, level)
  conditionNode.comparison = comparison

  if (node.callee.name === 'string.match') {
    setConditionFieldFromArg(conditionNode, node.arguments[1], options)

    const patternArg = node.arguments[0]
    if (!patternArg) {
      return conditionNode
    }

    if (patternArg.type === 'Literal') {
      conditionNode.value = patternArg.value
      conditionNode.valueIsLiteral = true
    } else if (patternArg.type === 'Identifier' || patternArg.type === 'MemberExpression') {
      conditionNode.value = resolveFieldNameFromAst(patternArg)
    }

    return conditionNode
  }

  setConditionFieldFromArg(conditionNode, node.arguments[0], options)
  const valueArg = node.arguments[1]

  if (valueArg?.type === 'Literal') {
    conditionNode.value = valueArg.value
    conditionNode.valueIsLiteral = true
  } else if (valueArg && (valueArg.type === 'Identifier' || valueArg.type === 'MemberExpression')) {
    conditionNode.value = resolveFieldNameFromAst(valueArg)
  }

  return conditionNode
}

export const callStringConditionRule: AstNodeRuleDefinition<CallExpressionNode> = {
  name: 'string-condition-call',
  priority: 90,
  handler: tryHandleStringConditionCall,
}
