import type { TreeNode } from '../../types'
import type { GenerateNodeExpressionFn, GeneratorContext } from '../nodeExpressionGenerator.types'
import { hasParameterContent, resolveParameterExpressionValue } from './parameters'
import type { BuildFunctionCallExpressionOptions } from './types'

function expandArrayParameters(parameters: unknown[]): string {
  const expanded: string[] = []
  parameters.forEach((param) => {
    if (Array.isArray(param)) {
      param.forEach((item) => {
        if (typeof item === 'string') {
          expanded.push(`"${item}"`)
        } else {
          expanded.push(String(item))
        }
      })
      return
    }

    expanded.push(String(param))
  })

  return expanded.join(', ')
}

function stringifyParameters(parameters: unknown[], options: BuildFunctionCallExpressionOptions): string {
  if (options.expandArrayValueParameters) {
    return expandArrayParameters(parameters)
  }
  return parameters.join(', ')
}

export function buildFunctionCallExpression(
  node: TreeNode,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
  options: BuildFunctionCallExpressionOptions = {},
): string {
  if (!node.functionName || !node.parameters) {
    return ''
  }

  const parameters = node.parameters
    .filter(hasParameterContent)
    .map((param) => resolveParameterExpressionValue(node, param, context, generateNodeExpression, options))

  return `${node.functionName}(${stringifyParameters(parameters, options)})`
}
