/**
 * AST到TreeNode转换器
 * 负责将抽象语法树转换为表达式树节点
 */

import type { TreeNode } from '../types'
import { createGroupNode } from '../utils'
import type { ASTNode } from './ast.types'
import type { ConversionContext } from './astToTreeNode.types'
import { handleBinaryExpressionNode } from './astToTreeNode.convert.binary'
import { handleCallExpressionNode } from './astToTreeNode.convert.call'

function collectLogicalOperands(expression: ASTNode, targetOperator: string): ASTNode[] {
  if (expression.type === 'LogicalExpression' && expression.operator === targetOperator) {
    return [
      ...collectLogicalOperands(expression.left, targetOperator),
      ...collectLogicalOperands(expression.right, targetOperator),
    ]
  }
  return [expression]
}

export function convertASTToTreeNodes(ast: ASTNode, context: ConversionContext): TreeNode[] {
  const convert = (node: ASTNode, level = 0, parentId?: string): TreeNode => {
    switch (node.type) {
      case 'LogicalExpression': {
        const groupNode = createGroupNode(parentId, level)
        groupNode.operator = node.operator === '&&' ? 'AND' : 'OR'

        const operands = collectLogicalOperands(node, node.operator)
        groupNode.children = operands.map((operand) => convert(operand, level + 1, groupNode.id))

        return groupNode
      }

      case 'BinaryExpression':
        return handleBinaryExpressionNode({
          node,
          level,
          parentId,
          context,
          convert,
        })

      case 'UnaryExpression': {
        const argumentNode = convert(node.argument, level, parentId)
        argumentNode.isNegated = true
        return argumentNode
      }

      case 'CallExpression':
        return handleCallExpressionNode({
          node,
          level,
          parentId,
          context,
          convert,
        })

      case 'GroupExpression':
        return convert(node.expression, level, parentId)

      default:
        throw new Error(`Unsupported AST node type: ${node.type}`)
    }
  }

  const rootNode = convert(ast, 0)

  if (rootNode.type !== 'group') {
    const wrapperGroup = createGroupNode(undefined, 0)
    wrapperGroup.operator = 'AND'
    wrapperGroup.children = [rootNode]
    rootNode.parentId = wrapperGroup.id
    rootNode.level = 1
    return [wrapperGroup]
  }

  return [rootNode]
}
