import type { TreeNode } from '../../types'
import type { GeneratorContext } from '../nodeExpressionGenerator.types'
import { getFieldConditionDataType } from './data-type'
import { isFunctionExpression } from './function-expression'

export function formatFieldComparisonValue(
  node: TreeNode,
  context: GeneratorContext,
): string | number | boolean | unknown {
  const value = node.value
  const userSelectedDataType = getFieldConditionDataType(node, context)

  if (typeof value === 'string' && value !== 'nil' && value !== '') {
    if (node.valueIsLiteral === true) {
      if (userSelectedDataType === 'number' || userSelectedDataType === 'boolean') {
        return value
      }
      if (!value.startsWith('"') && !value.startsWith('\'')) {
        return `"${value}"`
      }
      return value
    }

    const isFieldReference = context.availableFields.some((field) => field.value === value)
    const isMarkedAsField = node.valueIsField === true

    if (isFieldReference || isFunctionExpression(value) || isMarkedAsField) {
      return value
    }

    if (userSelectedDataType === 'number' || userSelectedDataType === 'boolean') {
      return value
    }

    if (!value.startsWith('"') && !value.startsWith('\'')) {
      return `"${value}"`
    }

    return value
  }

  if (typeof value === 'number') {
    if (userSelectedDataType === 'string') {
      return `"${value}"`
    }
    return String(value)
  }

  if (typeof value === 'boolean') {
    return String(value)
  }

  return value
}
