import { createConditionNode } from '../utils'
import type { CallExpressionNode } from './ast.types'
import type { AstNodeRuleDefinition } from './astToTreeNode.convert.rule-registry'
import {
  type LiteralDataType,
  filterNonNull,
  resolveSimpleNodeValue,
  setNodeDataType,
} from './astToTreeNode.convert.helpers'
import { setConditionFieldFromArg } from './astToTreeNode.convert.call.rule.shared'

function tryHandleIpInNetmaskCall(
  options: Parameters<AstNodeRuleDefinition<CallExpressionNode>['handler']>[0],
) {
  const { node, level, parentId, context } = options
  if (node.callee.name !== 'IPScene.isIpInNetmaskList' || node.arguments.length !== 2) {
    return null
  }

  const secondArg = node.arguments[1]
  if (!(secondArg.type === 'CallExpression' && secondArg.callee.name === 'seq.list')) {
    return null
  }

  const conditionNode = createConditionNode(parentId, level)
  conditionNode.comparison = 'isIpInNetmaskList'
  setConditionFieldFromArg(conditionNode, node.arguments[0], options)

  let detectedDataType: LiteralDataType = 'string'
  const listValues = secondArg.arguments.map((arg) => {
    if (arg.type === 'Literal' && (arg.dataType === 'string' || typeof arg.value === 'string')) {
      detectedDataType = 'string'
    }
    return resolveSimpleNodeValue(arg)
  }).filter(filterNonNull)

  conditionNode.value = listValues
  setNodeDataType(context, conditionNode.id, 'condition_value', detectedDataType)
  return conditionNode
}

export const callIpInNetmaskRule: AstNodeRuleDefinition<CallExpressionNode> = {
  name: 'ip-in-netmask-call',
  priority: 110,
  handler: tryHandleIpInNetmaskCall,
}
