import type { FieldOption } from '../../types'

const PRIORITY_FIELDS = [
  'ip_user',
  'token_user',
  'client_ip',
  'uuid',
  'response.status',
  'request.method',
  'request.uri',
  'request.url',
  'service_id',
  'upstream',
  'latency',
  'start_time',
  'user',
  'username',
  'id',
  'status',
  'time',
  'timestamp',
]

export function sortFieldOptions(fields: FieldOption[]): FieldOption[] {
  return fields.sort((a, b) => {
    const aPriority = PRIORITY_FIELDS.findIndex((field) =>
      a.value === field || a.value.toLowerCase().includes(field.toLowerCase()),
    )
    const bPriority = PRIORITY_FIELDS.findIndex((field) =>
      b.value === field || b.value.toLowerCase().includes(field.toLowerCase()),
    )

    if (aPriority !== -1 && bPriority !== -1) {
      return aPriority - bPriority
    }
    if (aPriority !== -1) return -1
    if (bPriority !== -1) return 1

    const aDepth = a.value.split('.').length
    const bDepth = b.value.split('.').length
    if (aDepth !== bDepth) {
      return aDepth - bDepth
    }

    return a.value.localeCompare(b.value)
  })
}
