import type { TreeNode } from '../../types'
import { validateFieldConditionNode } from './conditionValidation'
import { createFunctionCatalog } from './functionCatalog'
import { validateFunctionNode } from './functionValidation'
import { validateGroupNode } from './groupValidation'
import type { ValidationError, ValidationNode } from './types'

export type { ValidationError } from './types'

/**
 * 验证TreeNode数组
 * @param nodes TreeNode数组
 * @returns 验证错误数组
 */
export function validateExpression(nodes: TreeNode[]): ValidationError[] {
  const errors: ValidationError[] = []
  const functionCatalog = createFunctionCatalog()

  const validateNode = (node: ValidationNode): void => {
    if (node.type === 'group') {
      validateGroupNode(
        {
          id: node.id,
          expanded: node.expanded,
          children: node.children as ValidationNode[] | undefined,
        },
        errors,
        validateNode,
      )
      return
    }

    if (node.type === 'condition') {
      if (node.functionName) {
        validateFunctionNode(node, errors, functionCatalog)
      } else {
        validateFieldConditionNode(node, errors)
      }
      return
    }

    if (node.type === 'function') {
      validateFunctionNode(node, errors, functionCatalog, { requireFunctionName: true })
    }
  }

  nodes.forEach((node) => validateNode(node as ValidationNode))
  return errors
}
