import { createConditionNode } from '../utils'
import type { CallExpressionNode, LiteralNode } from './ast.types'
import type { AstNodeRuleDefinition } from './astToTreeNode.convert.rule-registry'
import {
  type LiteralDataType,
  filterNonNull,
  resolveSimpleNodeValue,
  setNodeDataType,
} from './astToTreeNode.convert.helpers'
import { setConditionFieldFromArg } from './astToTreeNode.convert.call.rule.shared'

function detectBelongValueDataType(current: LiteralDataType, literal: LiteralNode): LiteralDataType {
  if (current !== 'string') return current
  if (literal.dataType === 'number') return 'number'
  if (literal.dataType === 'keyword' && (literal.value === 'true' || literal.value === 'false')) {
    return 'boolean'
  }
  return 'string'
}

function tryHandleBelongCall(
  options: Parameters<AstNodeRuleDefinition<CallExpressionNode>['handler']>[0],
) {
  const { node, level, parentId, context } = options
  if (node.callee.name !== 'seq.some' || node.arguments.length !== 2) {
    return null
  }

  const lambdaArg = node.arguments[1]
  if (lambdaArg.type !== 'LambdaExpression') {
    return null
  }

  const lambdaBody = lambdaArg.body
  if (!(lambdaBody.type === 'CallExpression'
    && lambdaBody.callee.name === 'include'
    && lambdaBody.arguments.length === 2)) {
    return null
  }

  const includeFirstArg = lambdaBody.arguments[0]
  if (!(includeFirstArg.type === 'CallExpression' && includeFirstArg.callee.name === 'seq.list')) {
    return null
  }

  const conditionNode = createConditionNode(parentId, level)
  conditionNode.comparison = 'belong'
  setConditionFieldFromArg(conditionNode, node.arguments[0], options)

  let detectedDataType: LiteralDataType = 'string'
  const listValues = includeFirstArg.arguments.map((arg) => {
    if (arg.type === 'Literal') {
      detectedDataType = detectBelongValueDataType(detectedDataType, arg)
    }
    return resolveSimpleNodeValue(arg)
  }).filter(filterNonNull)

  conditionNode.value = listValues
  setNodeDataType(context, conditionNode.id, 'condition_value', detectedDataType)
  return conditionNode
}

export const callBelongRule: AstNodeRuleDefinition<CallExpressionNode> = {
  name: 'belong-call',
  priority: 100,
  handler: tryHandleBelongCall,
}
