import type { Token } from '../tokenizer/index'

export type ParserToken = Token | { type: 'EOF', value: '' }

const EOF_TOKEN: ParserToken = { type: 'EOF', value: '' }

export interface ParserRuntime {
  position: number
  currentToken: ParserToken
  tokens: Token[]
}

export function createParserRuntime(tokens: Token[]): ParserRuntime {
  return {
    position: 0,
    currentToken: tokens[0] || EOF_TOKEN,
    tokens,
  }
}

export function advance(runtime: ParserRuntime): void {
  runtime.position += 1
  runtime.currentToken = runtime.tokens[runtime.position] || EOF_TOKEN
}
