import type { NodeValue } from '../../types'

function parseArrayValues(value: NodeValue): unknown[] {
  if (Array.isArray(value)) {
    return value
  }

  if (typeof value !== 'string') {
    return []
  }

  try {
    const parsed = JSON.parse(value) as unknown
    return Array.isArray(parsed) ? parsed : [value]
  } catch {
    return [value]
  }
}

function toAviatorArrayLiteral(values: unknown[], dataType: string): string {
  return values
    .map((value) => {
      if (dataType === 'number' || dataType === 'boolean') {
        return String(value)
      }

      if (typeof value === 'string') {
        return `"${value}"`
      }
      return `"${String(value)}"`
    })
    .join(', ')
}

export function getAviatorArrayLiteral(value: NodeValue, dataType: string): string {
  return toAviatorArrayLiteral(parseArrayValues(value), dataType)
}
