import type { TreeNode } from '../types'
import { generateFieldModeConditionExpression } from './nodeExpressionGenerator.condition.field-mode'
import { generateFunctionModeConditionExpression } from './nodeExpressionGenerator.condition.function-mode'
import type { GenerateNodeExpressionFn, GeneratorContext } from './nodeExpressionGenerator.types'

export function generateConditionNodeExpression(
  node: TreeNode,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
): string {
  if (node.functionName) {
    return generateFunctionModeConditionExpression(node, context, generateNodeExpression)
  }

  return generateFieldModeConditionExpression(node, context)
}
