import type { TreeNode } from '../types'
import type { GenerateNodeExpressionFn, GeneratorContext } from './nodeExpressionGenerator.types'

export function generateGroupNodeExpression(
  node: TreeNode,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
): string {
  if (!node.children || node.children.length === 0) return ''
  const childExpressions = node.children
    .map((child) => generateNodeExpression(child, context))
    .filter((expr) => expr)
  if (childExpressions.length === 0) return ''

  const operator = node.operator === 'OR' ? ' || ' : ' && '

  // 处理分组取反
  if (node.isNegated) {
    const joinedExpression = childExpressions.join(operator)
    return `!(${joinedExpression})`
  }

  // 非取反情况
  if (childExpressions.length === 1) {
    if (node.level > 0) {
      return `(${childExpressions[0]})`
    }
    return childExpressions[0]
  } else {
    const joinedExpression = childExpressions.join(operator)

    if (node.level > 0) {
      return `(${joinedExpression})`
    }

    const needsParentheses = node.operator === 'OR'
      && childExpressions.some((expr) => expr.includes(' && '))

    if (needsParentheses) {
      return `(${joinedExpression})`
    } else {
      return joinedExpression
    }
  }
}
