import type { BinaryExpressionNode } from './ast.types'
import type { AstNodeRuleDefinition } from './astToTreeNode.convert.rule-registry'
import { isNilLiteral } from './astToTreeNode.convert.helpers'

function tryHandleStringConditionComparison(
  options: Parameters<AstNodeRuleDefinition<BinaryExpressionNode>['handler']>[0],
) {
  const { node, level, parentId, convert } = options
  if (node.left.type !== 'CallExpression') {
    return null
  }

  const booleanConditionFunctions = new Set(['string.contains', 'string.startsWith', 'string.endsWith'])
  if (booleanConditionFunctions.has(node.left.callee.name)) {
    return convert(node.left, level, parentId)
  }

  if (node.left.callee.name === 'string.match') {
    const conditionNode = convert(node.left, level, parentId)
    conditionNode.comparison = 'match'
    if (isNilLiteral(node.right) && node.operator === '==') {
      conditionNode.isNegated = true
    }
    return conditionNode
  }

  return null
}

export const binaryStringConditionRule: AstNodeRuleDefinition<BinaryExpressionNode> = {
  name: 'string-condition-comparison',
  priority: 90,
  handler: tryHandleStringConditionComparison,
}
