import type { TreeNode } from '../types'
import {
  type BuildFunctionCallExpressionOptions,
  buildFunctionCallExpression,
  formatFunctionComparisonValue,
  isBooleanReturnFunction,
  isNilOrEmptyComparison,
} from './function-shared'
import type { GenerateNodeExpressionFn, GeneratorContext } from './nodeExpressionGenerator.types'

export interface GenerateFunctionModeExpressionOptions {
  call?: BuildFunctionCallExpressionOptions
  treatComparisonValueAsField?: boolean
  negationStrategy?: 'none' | 'boolean-only' | 'wrap-final'
}

function applyNegation(expression: string, node: TreeNode, strategy: GenerateFunctionModeExpressionOptions['negationStrategy']): string {
  if (!node.isNegated) {
    return expression
  }

  if (strategy === 'boolean-only') {
    return `!${expression}`
  }

  if (strategy === 'wrap-final') {
    return `!(${expression})`
  }

  return expression
}

export function generateFunctionModeExpression(
  node: TreeNode,
  context: GeneratorContext,
  generateNodeExpression: GenerateNodeExpressionFn,
  options: GenerateFunctionModeExpressionOptions = {},
): string {
  if (!node.functionName || !node.parameters) {
    return ''
  }

  const functionCall = buildFunctionCallExpression(node, context, generateNodeExpression, options.call)
  const isBooleanFunction = isBooleanReturnFunction(node.functionName)

  if (isBooleanFunction) {
    return applyNegation(functionCall, node, options.negationStrategy)
  }

  let expression = functionCall
  if (node.comparison) {
    if (isNilOrEmptyComparison(node.comparison)) {
      expression = `${functionCall} ${node.comparison}`
    } else if (node.value !== undefined && node.value !== '') {
      const nodeDataTypes = context.parameterDataTypes.get(node.id)
      const dataTypeKey = node.functionName || 'condition_value'
      const userSelectedDataType = nodeDataTypes?.get(dataTypeKey) || 'string'
      const comparisonValue = formatFunctionComparisonValue({
        value: node.value,
        userSelectedDataType,
        treatAsField: options.treatComparisonValueAsField,
      })
      expression = `${functionCall} ${node.comparison} ${comparisonValue}`
    }
  }

  if (options.negationStrategy === 'wrap-final') {
    return applyNegation(expression, node, options.negationStrategy)
  }

  return expression
}
