import type { TreeNode } from '../../types'
import { generateNodeId } from './id'

/**
 * 创建新的分组节点
 */
export function createGroupNode(parentId?: string, level: number = 0): TreeNode {
  return {
    id: generateNodeId(),
    type: 'group',
    level,
    parentId,
    operator: 'AND',
    children: [],
    expanded: true,
  }
}
