import type { FunctionParameter, NodeValue } from '../../types'

const COMPOUND_COMPARISON_OPERATORS = new Set(['== nil', '!= nil', '== \'\'', '!= \'\''])

export function hasComparableValue(value: NodeValue | undefined): boolean {
  return value !== undefined && value !== ''
}

export function hasParameterValue(parameter: FunctionParameter | undefined): boolean {
  if (!parameter) {
    return false
  }

  const hasValue = parameter.value !== undefined && parameter.value !== ''
  const hasNestedNode = Boolean(parameter.isNested && parameter.nestedNode)
  return hasValue || hasNestedNode
}

export function requiresComparisonValue(comparison: string): boolean {
  return !COMPOUND_COMPARISON_OPERATORS.has(comparison)
}
