import { NIL_OR_EMPTY_COMPARISONS } from './constants'
import type { FormatFunctionComparisonValueOptions } from './types'

export function isNilOrEmptyComparison(comparison?: string): boolean {
  if (!comparison) {
    return false
  }
  return NIL_OR_EMPTY_COMPARISONS.has(comparison)
}

export function formatFunctionComparisonValue(options: FormatFunctionComparisonValueOptions): unknown {
  const { userSelectedDataType, treatAsField = false } = options
  let { value } = options

  if (typeof value === 'string' && value !== 'nil' && value !== '') {
    if (treatAsField) {
      return value
    }
    if (userSelectedDataType === 'number' || userSelectedDataType === 'boolean') {
      return value
    }
    if (!value.startsWith('"') && !value.startsWith('\'')) {
      value = `"${value}"`
    }
    return value
  }

  if (typeof value === 'number') {
    if (userSelectedDataType === 'string') {
      return `"${value}"`
    }
    return String(value)
  }

  if (typeof value === 'boolean') {
    return String(value)
  }

  return value
}
